+    #[test]
+    fn test_vacuum_rejects_active_transaction_and_savepoint() {
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("vacuum-active-txn.db");
+        let target_path = dir.path().join("vacuum-active-txn-copy.db");
+        let db_path_str = db_path.to_string_lossy().into_owned();
+        let target_path_str = target_path.to_string_lossy().into_owned();
+
+        let conn = Connection::open(&db_path_str).unwrap();
+        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, name TEXT);")
+            .unwrap();
+        conn.execute("INSERT INTO t VALUES (1, 'alpha');").unwrap();
+
+        conn.execute("BEGIN;").unwrap();
+        let err = conn.execute("VACUUM;").unwrap_err();
+        assert!(
+            matches!(err, FrankenError::VacuumWithinTransaction),
+            "expected active transaction guard, got {err:?}"
+        );
+        conn.execute("ROLLBACK;").unwrap();
+
+        conn.execute("SAVEPOINT sp;").unwrap();
+        let err = conn
+            .execute_with_params(
+                "VACUUM INTO ?1;",
+                &[SqliteValue::Text(target_path_str.clone().into())],
+            )
+            .unwrap_err();
+        assert!(
+            matches!(err, FrankenError::VacuumWithinTransaction),
+            "expected active savepoint guard, got {err:?}"
+        );
+        conn.execute("ROLLBACK;").unwrap();
+        assert!(
+            !target_path.exists(),
+            "VACUUM INTO should not create a target file when rejected in-transaction"
+        );
+    }
